export const TypicalTailwindCSSUsage: Story = {
	parameters: {
		...defineDarkModeParam({
			classTarget: 'html',
			darkClass: 'dark',
			stylePreview: true
		}),
		...defineDocsParam({
			description: {
				story: [
					'In typical Tailwind CSS usage,',
					'you would place the dark class at the html element',
					'so that you can apply style to the `body` element.'
